+		Priority:  2,
+		IssueType: types.TypeTask,
+		NoHistory: true,
+	}
+	if err := s.CreateIssue(ctx, noHistoryBead, "test"); err != nil {
+		t.Fatalf("CreateIssue (NoHistory): %v", err)
+	}
